#include <iostream>
#include <string>

int main() {
    int x;
    std::cin >> x;
    std::string ans;
    switch (x) {
        case 5: ans = "Onts"; break;
        case 4: ans = "Sain"; break;
        case 3: ans = "Dund"; break;
        case 2: ans = "Muu"; break;
    }
    std::cout << ans << std::endl;
    return 0;
}
